const data = $input.first().json.body || $input.first().json;
const incident_id = data.incident_id;
const service = data.service;
const display = data.display || service;
const error = data.error || '';
const root_cause = data.root_cause || '';
const fix_diff = data.fix_diff || '';
const impact = data.impact || 0;
const historical_ref = data.historical_incident || 'N/A';
const source_file = data.source_file || '';
const source_line = data.source_line || '';
const demo_url = 'https://campbell-ops-demo.dev.hyperplane.dev';

return [{
  json: {
    incident_id,
    service,
    display,
    error,
    root_cause,
    fix_diff,
    impact,
    historical_ref,
    source_file,
    source_line,
    approve_url: `${demo_url}/api/webhooks/approve/${incident_id}`,
    reject_url: `${demo_url}/api/webhooks/reject/${incident_id}`,
    dashboard_url: `${demo_url}`,
    review_text: `🔍 **Code Review Required — ${display}**\n\n**Error**: \`${error.substring(0, 80)}\`\n**File**: \`${source_file}:${source_line}\`\n**Root Cause**: ${root_cause.substring(0, 200)}\n\n**Proposed Fix (diff)**:\n\`\`\`diff\n${fix_diff}\n\`\`\`\n\n💰 **$${impact.toLocaleString()}** at risk | Historical ref: **${historical_ref}**\n\n_Campbell Ops Co-Pilot — Quantitative Trading Infrastructure_`
  }
}];

